12	const DEDUCTIBLE = 100;
13	const CAP_MULTIPLIER = 2;
14	
15	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	};
23	
