33	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
34	type Customer = { yearsWithMHPCO: number };
35	type Damage = { itemType: string; amount: number };
36	type Incident = { cause: string; damages: Damage[] };
37	type QuoteStep = { op: "quote"; items: Item[] };
38	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
39	type Step = QuoteStep | ClaimStep;
40	type Scenario = { customer: Customer; steps: Step[] };
41	
42	type QuoteResult = { premium: number };
43	type ClaimResult = { payout: number; remainingCap: number };
44	type Result = QuoteResult | ClaimResult;
45	
46	type Policy = { items: Item[]; cap: number; remainingCap: number };
47	
48	const isComponent = (item: Item) => COMPONENT_TYPES.has(item.type);
49	
50	const baseForCount = (count: number): number =>
51	  count === BLOCK_SIZE ? COMPONENT_BLOCK_BASE : count * COMPONENT_BASE;
52	
53	const countByType = (items: Item[]): Record<string, number> => {
54	  const counts: Record<string, number> = {};
55	  for (const item of items) counts[item.type] = (counts[item.type] ?? 0) + 1;
56	  return counts;
57	};
58	
59	const componentBase = (items: Item[]): number =>
60	  Object.values(countByType(items)).reduce((sum, count) => sum + baseForCount(count), 0);
61	
62	const itemBase = (item: Item): number => BASE_PREMIUM[item.type];
63	
64	const itemSurcharge = (item: Item): number => {
65	  const base = itemBase(item);
66	  let surcharge = 0;
67	  if (item.cursed) surcharge += base * CURSE_RATE;
68	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) surcharge += base * HIGH_ENCHANTMENT_RATE;
69	  return surcharge;
70	};
71	
72	const quotePremium = (items: Item[], customer: Customer, contractIndex: number): number => {
73	  const components = items.filter(isComponent);
74	  const mains = items.filter((i) => !isComponent(i));
75	  const policyBase = mains.reduce((sum, item) => sum + itemBase(item), 0) + componentBase(components);
76	  const itemSurcharges = mains.reduce((sum, item) => sum + itemSurcharge(item), 0);
77	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
78	  const loyalty = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? policyBase * LOYALTY_RATE : 0;
79	  const followUp = contractIndex > 0 ? policyBase * FOLLOWUP_RATE : 0;
80	  return Math.ceil(policyBase + itemSurcharges + firstInsurance - loyalty - followUp + PROCESSING_FEE);
81	};
82	
83	const policyInsuranceSum = (items: Item[]): number =>
84	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
85	
86	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
87	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
88	
89	const damagePayout = (damage: Damage, item: Item | undefined): number => {
90	  const enchantment = item?.enchantment ?? 0;
91	  const reimbursableFraction = enchantment >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
92	    ? HIGH_ENCHANTMENT_PAYOUT_RATE
93	    : 1;
94	  return Math.max(0, damage.amount * reimbursableFraction - DEDUCTIBLE);
95	};
96	
97	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
98	  const grossPayout = incident.damages.reduce((sum, d) => {
99	    const item = policy.items.find((i) => i.type === d.itemType);
100	    return sum + damagePayout(d, item);
101	  }, 0);
102	  const payout = Math.min(grossPayout, policy.remainingCap);
103	  policy.remainingCap -= payout;
104	  return { payout: Math.floor(payout), remainingCap: Math.floor(policy.remainingCap) };
105	};
106	
107	export const runScenario = (scenario: Scenario): { results: Result[] } => {
108	  const policies: Record<number, Policy> = {};
109	  const results: Result[] = scenario.steps.map((step, index) => {
110	    if (step.op === "quote") {
111	      const sum = policyInsuranceSum(step.items);
112	      policies[index] = { items: step.items, cap: sum * CAP_MULTIPLIER, remainingCap: sum * CAP_MULTIPLIER };
113	      return { premium: quotePremium(step.items, scenario.customer, index) };
114	    }
115	    return processClaim(policies[step.policy], step.incident);
116	  });
117	  return { results };
118	};
